```razor
@page "/"
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h2 class="display-5 fw-bold">Welcome to the University Course Catalog</h2>
    <p class="lead text-muted">Browse our departments and courses, or enroll directly online.</p>
</div>

@if (featuredCourses is not null && featuredCourses.Count > 0)
{
    <section class="mb-5">
        <h3 class="mb-3">⭐ Featured Courses</h3>
        <div class="row">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Code — @course.Title</h5>
                            <p class="card-text text-muted">@course.Credits credits · @course.InstructorName</p>
                            <p class="card-text">@course.Description</p>
                        </div>
                        <div class="card-footer bg-transparent">
                            <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>
}

@if (departments is not null && departments.Count > 0)
{
    <section>
        <h3 class="mb-3">🏛️ Departments</h3>
        <div class="list-group">
            @foreach (var dept in departments)
            {
                <a href="/courses?DepartmentId=@dept.Id" class="list-group-item list-group-item-action">
                    <strong>@dept.Code</strong> — @dept.Name
                    <br />
                    <small class="text-muted">@dept.Description</small>
                </a>
            }
        </div>
    </section>
}

@code {
    private List<Course>? featuredCourses;
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        departments = await CatalogService.GetDepartmentsAsync();
    }
}
```

