```razor
@page "/enroll"
@inject ICatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h2 class="mb-4">Course Enrollment</h2>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Submitted!</h4>
