@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for the selected course has been submitted successfully.</p>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <EditForm Model="Model" method="post" FormName="EnrollmentForm" OnValidSubmit="HandleSubmit">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Student Name</label>
            <InputText id="studentName" @bind-Value="Model.StudentName" class="form-control" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="0">-- Select a course --</option>
                @if (courses is not null)
                {
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code — @course.Title</option>
                    }
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment</button>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    private List<Course>? courses;
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        courses = await CatalogService.GetCoursesAsync();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private async Task HandleSubmit()
    {
        await CatalogService.SubmitEnrollmentRequestAsync(Model);
        submitted = true;
    }
}
